const assetMap = new Map([
  ["/apple-touch-icon.png", { contentType: "image/png", base64: "", cacheControl: "public, max-age=86400" }],
  ["/favicon-16x16.png", { contentType: "image/png", base64: "", cacheControl: "public, max-age=86400" }],
  ["/favicon-32x32.png", { contentType: "image/png", base64: "", cacheControl: "public, max-age=86400" }],
  ["/site.webmanifest", { contentType: "application/manifest+json; charset=UTF-8", text: "{\n  \"name\": \"Local Bridge Checker\",\n  \"short_name\": \"Local Bridge\",\n  \"description\": \"Check the local Local Bridge API and desktop file listing from the browser.\",\n  \"start_url\": \"/\",\n  \"display\": \"standalone\",\n  \"background_color\": \"#f4f2ed\",\n  \"theme_color\": \"#d85f3c\",\n  \"icons\": [\n    {\n      \"src\": \"/web-app-manifest-192x192.png\",\n      \"sizes\": \"192x192\",\n      \"type\": \"image/png\"\n    },\n    {\n      \"src\": \"/web-app-manifest-512x512.png\",\n      \"sizes\": \"512x512\",\n      \"type\": \"image/png\"\n    }\n  ]\n}\n", cacheControl: "public, max-age=86400" }],
  ["/web-app-manifest-192x192.png", { contentType: "image/png", base64: "", cacheControl: "public, max-age=86400" }],
  ["/web-app-manifest-512x512.png", { contentType: "image/png", base64: "", cacheControl: "public, max-age=86400" }],
])

function decodeBase64(base64) {
  return Uint8Array.from(atob(base64), (char) => char.charCodeAt(0))
}

export function getAsset(pathname) {
  return assetMap.get(pathname) || null
}

export function getAssetResponse(asset) {
  return new Response(asset.text ?? decodeBase64(asset.base64), {
    headers: {
      'content-type': asset.contentType,
      'cache-control': asset.cacheControl
    }
  })
}

